let redis_url = JSON.parse(env.get("REDIS_URL"))
const cluster = new Redis.Cluster(redis_url);


const RPC_URL = "http://aria2:6800/jsonrpc";
const WS_URL = "ws://aria2:6800/jsonrpc";
const RPC_SECRET = "secret";

const ws = new WebSocket(WS_URL);

ws.on("message", data => {
    const response = JSON.parse(data);
    if (response.method === "aria2.onDownloadComplete") {
        const gid = response.params[0].gid;
        console.log(`Download completed for GID: ${gid}`);
    }
});

// Job processor function
const processDownloadJob = async (job) => {
    const { href } = job.data;

    const aria2 = {
        jsonrpc: "2.0",
        method: "aria2.addUri",
        id: "1",
        params: [`token:${RPC_SECRET}`, [href]]
    };


        try {
            const response = await axios.post(RPC_URL, aria2);
            const gid = response.data.result;
            console.log(`Download requested with GID: ${gid}`);

            // Wait for completion using WebSocket events
            await new Promise(resolve => {
                node.log(`promise`);
                ws.on("message", data => {
                    node.log(`message received`);
                    const event = JSON.parse(data);
                    if (event.method === "aria2.onDownloadComplete" && event.params[0].gid === gid) {
                        node.log(`Download completed: ${href}`);
                        resolve();
                    } else if (event.method === "aria2.onDownloadError" && event.params[0].gid === gid) {
                        node.log(`Download error: ${href}`);
                        resolve();
                    }

                });
            });

            console.log(`Finished processing: ${href}`);

        return { status: 'sent', timestamp: new Date().toISOString() };

    } catch (error) {
        node.error(`Job ${job.id} failed: ${error.message}`);

        // Send error message to Node-RED flow
        node.send({
            payload: {
                type: 'job-failed',
                jobId: job.id,
                error: error.message
            }
        });

        throw error;
    }
};

// Create worker with prefix hash tag
const downloadWorker = new bullmq.Worker('download-aria2', processDownloadJob, {
    connection: cluster,
    prefix: '{titine}', // Hash tag ensures all keys go to same slot
    concurrency: 5,
    limiter: {
        max: 10,
        duration: 1000
    }
});

// Worker event handlers
downloadWorker.on('completed', (job, result) => {
    node.log(`Job ${job.id} completed with result:`);
});

downloadWorker.on('failed', (job, err) => {
    node.error(`Job ${job.id} failed:`, err.message);
});

downloadWorker.on('progress', (job, progress) => {
    node.log(`Job ${job.id} progress: ${progress}%`);
});

// Store worker reference for cleanup
context.set('downloadWorker', downloadWorker);

msg.payload = {
    status: 'Worker started',
    queueName: 'download-aria2',
    concurrency: 5
};

return msg;

