const redisNodes = JSON.parse(env.get("REDIS_URL"));
const subscribers = redisNodes.map(node => new redis(node));

subscribers.forEach((subscriber, index) => {
    let nodeInfo = `${redisNodes[index].host}:${redisNodes[index].port}`;

    // Enable keyspace notifications if not set
    subscriber.config("SET", "notify-keyspace-events", "Ex").catch(err =>
        console.error(`⚠️ Failed to enable key notifications on ${nodeInfo}:`, err));

    // Subscribe to key events
    subscriber.psubscribe("__keyevent@0__:expired", (err, count) => {
        if (err) {
            console.error(`❌ Subscription failed on ${nodeInfo}`, err);
        } else {
            console.log(`🔔 Listening for key events on ${nodeInfo}`);
        }
    });

    subscriber.on("pmessage", (pattern, channel, message) => {
        msg.payload = {
            event: channel,
            key: message
        };
        node.send(msg);
    });

});



return msg;

if (!context.get("redisSubscribers")) {
    const redisNodes = JSON.parse(env.get("REDIS_URL"));

    // Store the list of Redis subscribers globally
    const subscribers = redisNodes.map(node => new redis(node));
    context.set("redisSubscribers", subscribers);

    console.log("✅ Redis subscriptions initialized once!");
}


const subscribers = context.get("redisSubscribers");

subscribers.forEach((subscriber, index) => {
    let nodeInfo = `${JSON.parse(env.get("REDIS_URL"))[index].host}:${JSON.parse(env.get("REDIS_URL"))[index].port}`;

    // Only subscribe if this node doesn't already have listeners
    if (!context.get(`listener_${nodeInfo}`)) {
        subscriber.psubscribe("__keyevent@*__:expired", (err, count) => {
            if (err) {
                console.error(`❌ Subscription failed on ${nodeInfo}`, err);
            } else {
                console.log(`🔔 Listening for key expirations on ${nodeInfo}`);
                context.set(`listener_${nodeInfo}`, true); // Mark listener as active
            }
        });


        subscriber.on("pmessage", (pattern, channel, message) => {
            msg.payload = {
                event: channel,
                key: message
            };
            node.send(msg);
        });
    } else {
        console.log(`⚠️ Listener already exists for ${nodeInfo}, skipping duplicate subscription.`);
    }
});
